计划名称 | 计划类型（必修/选修） | 适用人群（部门/岗位/标签） | 时间（建议/强制截止日） | 完成率 | 状态（草稿/进行中/已结束） | 操作 核心操作： •  新建计划（含从模板创建）  •  编辑/复制/删除/归档  •  启停状态（暂停后员工无法继续学习）  •  指派人员（支持按部门/岗位/标签/具体人员）  •  催学（批量发送消息）  •  查看进度（跳转到「进度监控」并自动筛选该计划）   设计细节： •  状态用不同颜色圆点标识（进行中=绿色，已结束=灰色，草稿=橙色）  •  完成率显示进度条 + 数字（如 68%）  •  支持按计划类型、状态、创建时间筛选  •  支持列排序（如按完成率倒序）',false,false,false,false,false,true,'','','学习计划',0,'1760761396972',522,'item','1760761437196',0,'',false,false,false,false,0);INSERT INTO "ManageMenu"("MM_Id","MM_AbbrName","MM_Color","MM_Complete","MM_Font","MM_Func","MM_Help","MM_IcoCode","MM_IcoColor","MM_IcoSize","MM_IcoX","MM_IcoY","MM_Intro","MM_IsBold","MM_IsChilds","MM_IsFixed","MM_IsItalic","MM_IsShow","MM_IsUse","MM_Link","MM_Marker","MM_Name","MM_Order","MM_PatId","MM_Root","MM_Type","MM_UID","MM_WinHeight","MM_WinID","MM_WinMax","MM_WinMin","MM_WinMove","MM_WinResize","MM_WinWidth") VALUES (43774,'','',0,'','func','','e732','',-5,0,0,'',false,false,false,false,false,true,'','','计划模板库',1,'1760761396972',522,'item','1775652453638',0,'',false,false,false,false,0);INSERT INTO "ManageMenu"("MM_Id","MM_AbbrName","MM_Color","MM_Complete","MM_Font","MM_Func","MM_Help","MM_IcoCode","MM_IcoColor","MM_IcoSize","MM_IcoX","MM_IcoY","MM_Intro","MM_IsBold","MM_IsChilds","MM_IsFixed","MM_IsItalic","MM_IsShow","MM_IsUse","MM_Link","MM_Marker","MM_Name","MM_Order","MM_PatId","MM_Root","MM_Type","MM_UID","MM_WinHeight","MM_WinID","MM_WinMax","MM_WinMin","MM_WinMove","MM_WinResize","MM_WinWidth") VALUES (43775,'','',0,'','func','','e60d','',-5,0,-2,'',false,false,false,false,false,true,'','','指派记录',2,'1760761396972',522,'item','1775652479804',0,'',false,false,false,false,0);INSERT INTO "ManageMenu"("MM_Id","MM_AbbrName","MM_Color","MM_Complete","MM_Font","MM_Func","MM_Help","MM_IcoCode","MM_IcoColor","MM_IcoSize","MM_IcoX","MM_IcoY","MM_Intro","MM_IsBold","MM_IsChilds","MM_IsFixed","MM_IsItalic","MM_IsShow","MM_IsUse","MM_Link","MM_Marker","MM_Name","MM_Order","MM_PatId","MM_Root","MM_Type","MM_UID","MM_WinHeig